func HasAttachmentWith(preds ...predicate.Attachment) predicate.AttachmentVersion {
	return predicate.AttachmentVersion(func(s *sql.Selector) {
		step := newAttachmentStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.AttachmentVersion) predicate.AttachmentVersion {
	return predicate.AttachmentVersion(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.AttachmentVersion) predicate.AttachmentVersion {
	return predicate.AttachmentVersion(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.AttachmentVersion) predicate.AttachmentVersion {
	return predicate.AttachmentVersion(sql.NotPredicates(p))
}
